// Multipart reassembly + Reading-wrapper unwrap (mirror of lib/reassemble.js)
var store = context.get('mp') || {};
function feed(o){
  if(o==null||typeof o!=='object'||o.MultiPart_ID===undefined) return o;
  var id=o.MultiPart_ID;
  var buf=store[id]||(store[id]=[]);
  buf.push(String(o.Data==null?'':o.Data));
  try{ var p=JSON.parse(buf.join('')); delete store[id]; return p; }
  catch(e){ return null; }
}
var parsed = feed(msg.payload);
context.set('mp', store);
if(parsed==null) return null;            // still buffering fragments
var r = (parsed && parsed.Reading && typeof parsed.Reading==='object') ? parsed.Reading : parsed;
if(!r || !r.Fs || !r.Samples){ node.warn('dyn/vib without waveform fields'); return null; }
msg.meta = { serial:r.Serial, id:r.ID, time:r.Time, Fs:r.Fs, Samples:r.Samples };
msg.axes = { X:r.X, Y:r.Y, Z:r.Z };
node.status({fill:'green',shape:'dot',text:'rd '+r.Serial+' #'+r.ID});
return msg;

// FFT -> single-sided spectrum -> downsample -> [chart, waterfall]
// (mirror of lib/fft.js; 6400 samples Hann-windowed and zero-padded to 8192)
function nextPow2(n){var p=1;while(p<n)p<<=1;return p;}
function hann(N){var w=new Float64Array(N);for(var i=0;i<N;i++)w[i]=0.5*(1-Math.cos(2*Math.PI*i/(N-1)));return w;}
function fft(re,im){var n=re.length;for(var i=1,j=0;i<n;i++){var bit=n>>1;for(;j&bit;bit>>=1)j^=bit;j^=bit;if(i<j){var tr=re[i];re[i]=re[j];re[j]=tr;var ti=im[i];im[i]=im[j];im[j]=ti;}}for(var L=2;L<=n;L<<=1){var ang=-2*Math.PI/L;var wr=Math.cos(ang),wi=Math.sin(ang);for(var s=0;s<n;s+=L){var cwr=1,cwi=0;for(var k=0;k<L/2;k++){var a=s+k,b=s+k+L/2;var vr=re[b]*cwr-im[b]*cwi;var vi=re[b]*cwi+im[b]*cwr;re[b]=re[a]-vr;im[b]=im[a]-vi;re[a]+=vr;im[a]+=vi;var ncwr=cwr*wr-cwi*wi;cwi=cwr*wi+cwi*wr;cwr=ncwr;}}}}
function spectrum(sig,Fs){var N0=sig.length;var w=hann(N0);var Nfft=nextPow2(N0);var re=new Float64Array(Nfft),im=new Float64Array(Nfft);var ws=0;for(var i=0;i<N0;i++){re[i]=sig[i]*w[i];ws+=w[i];}fft(re,im);var half=Nfft>>1;var mag=new Float64Array(half),fr=new Float64Array(half);var df=Fs/Nfft;for(var k=0;k<half;k++){var m=Math.sqrt(re[k]*re[k]+im[k]*im[k]);mag[k]=(k===0?1:2)*m/ws;fr[k]=k*df;}return {freqs:fr,mag:mag};}

var axis = flow.get('axis') || 'Z';
var sig = (msg.axes && msg.axes[axis]) ? msg.axes[axis] : null;
if(!sig || !sig.length){ node.warn('axis '+axis+' empty (WS200 is single-axis)'); return null; }
var sp = spectrum(sig, msg.meta.Fs);
var half = sp.mag.length;

var BINS = 256, step = half/BINS;
var bars = new Array(BINS), freqs = new Array(BINS);
for(var b=0;b<BINS;b++){
  var lo=Math.floor(b*step), hi=Math.floor((b+1)*step); if(hi<=lo)hi=lo+1;
  var mx=0, fAt=sp.freqs[lo];
  for(var k=lo;k<hi&&k<half;k++){ if(sp.mag[k]>mx){mx=sp.mag[k];fAt=sp.freqs[k];} }
  bars[b]=mx; freqs[b]=fAt;
}
var pts=[]; for(var c=0;c<BINS;c++) pts.push({x:Math.round(freqs[c]),y:bars[c]});
var chartMsg = { payload:[ {series:[axis], data:[pts], labels:['']} ] };
var wfMsg = { payload:{ axis:axis, serial:msg.meta.serial, time:msg.meta.time,
  fmax:Math.round(sp.freqs[half-1]), bins:bars } };
node.status({fill:'blue',shape:'dot',text:axis+' fft ok'});
return [chartMsg, wfMsg];

// dropdown -> flow context axis (applies to next reading)
flow.set('axis', msg.payload);
node.status({fill:'grey',shape:'ring',text:'axis='+msg.payload});
return null;
